SELECT DISTINCT u.user_name
FROM access_logs al
INNER JOIN users u ON al.user_id = u.user_id;

SELECT interrupt_name
FROM interrupt_events
WHERE enable_bit = 'yes';

SELECT COUNT(*) AS high_priority_config_count
FROM interrupt_configurations
WHERE priority = 0;

SELECT interrupt_type_name
FROM interrupt_event_types
WHERE interrupt_type_id = 0;

SELECT interrupt_source_name
FROM interrupt_sources
WHERE interrupt_source_id = 0;
